const source = $json.body ?? $json;
const binary = items[0].binary || {};
const firstBinaryKey = Object.keys(binary)[0] || null;

const pick = (...keys) => {
  for (const key of keys) {
    const value = source[key];
    if (value !== undefined && value !== null && String(value).trim() !== '') {
      return String(value).trim();
    }
  }
  return '';
};

const clienteNome = pick('cliente_nome', 'Nome do Cliente', 'nome_do_cliente', 'nomeCliente');
const segmento = pick('segmento', 'Segmento');
const prazoEntrega = pick('prazo_entrega', 'Prazo de Entrega', 'prazoEntrega', 'prazo');

if (!clienteNome) {
  throw new Error('Campo \"Nome do Cliente\" ausente.');
}

if (!segmento) {
  throw new Error('Campo \"Segmento\" ausente.');
}

if (!prazoEntrega) {
  throw new Error('Campo \"Prazo de Entrega\" ausente.');
}

if (!firstBinaryKey) {
  throw new Error('Envie o briefing em arquivo .txt no multipart/form-data.');
}

return [{
  json: {
    cliente_nome: clienteNome,
    segmento,
    prazo_entrega: prazoEntrega,
    arquivo_origem: firstBinaryKey,
    recebido_em: new Date().toISOString()
  },
  binary: {
    briefing_arquivo: binary[firstBinaryKey]
  }
}];

const cliente = $('Normalizar Entrada').item.json.cliente_nome;
const segmento = $('Normalizar Entrada').item.json.segmento;
const prazo = $('Normalizar Entrada').item.json.prazo_entrega;
const transcript = $json.texto_final;

const prompt = `Voce e o Briefing Expert Alpha.

Cliente: ${cliente}
Segmento: ${segmento}
Prazo de entrega: ${prazo}

Sua tarefa: ler a transcricao abaixo e devolver um briefing inicial claro, organizado e acionavel em portugues do Brasil.

Estruture a resposta nestas secoes:
1. Resumo executivo
2. Oferta principal
3. Publico-alvo
4. Dores e objecoes
5. Diferenciais
6. Metas e gargalos
7. Materiais e acessos pendentes
8. Proximos passos da Alpha
9. Perguntas pendentes

Use bullets curtos. Quando algo estiver faltando, marque como [PENDENTE].

TRANSCRICAO:
${transcript}`;

return [{
  json: {
    cliente_nome: cliente,
    segmento,
    prazo_entrega: prazo,
    transcript,
    prompt
  }
}];

