const board = $json.data?.boards?.[0];
if (!board) {
  throw new Error('Nao consegui localizar o board de briefing duplicado.');
}

const columns = board.columns || [];
const item = board.items_page?.items?.[0];
if (!item) {
  throw new Error('Nao achei o item CRIAR RESUMO DO CLIENTE no board de briefing.');
}

const normalize = (value) => String(value || '').normalize('NFD').replace(/[\u0300-\u036f]/g, '').toLowerCase();
const linkColumn = columns.find((column) => {
  const title = normalize(column.title);
  return title.includes('link') && title.includes('briefing');
});

if (!linkColumn) {
  throw new Error('Nao achei a coluna de Link do Briefing no board duplicado.');
}

return [{
  json: {
    board_id: $('Duplicar Board Briefing').item.json.data.duplicate_board.board.id,
    item_id: item.id,
    column_id: linkColumn.id,
    doc_url: $('Preparar Monday').item.json.doc_url
  }
}];

